+fn execute_benchmark_score(args: BenchmarkScoreArgs) -> Result<i32, String> {
+    let input = load_json_file::<PublicationGateInput>(&args.input)?;
+    let ctx = PublicationContext::new(
+        args.trace_id.clone(),
+        args.decision_id.clone(),
+        args.policy_id.clone(),
